#include <bits/stdc++.h>
using namespace std;
long long a[1000500];
int main()
{
    long long b,c,d=0,e;
    cin>>b;
    string h;
    for(long long i=0;i<b;i++){
        cin>>c;
        for(long long j=0;j<c;j++){
            cin>>h;
            if(h=="push"){
                cin>>e;
                a[d]=e;
                d++;
            }
            else if(h=="pop"){
                if(d==0){
                    cout<<"Empty"<<endl;
                }
                else{
                    d--;
                }
            }
            else if(h=="query"){
                if(d==0){
                    cout<<"Anguei!"<<endl;
                }
                else{
                    cout<<a[d-1]<<endl;
                }
            }
            else{
                cout<<d<<endl;
            }
        }
    }
    return 0;
}
